from __future__ import annotations

import logging
import secrets
import os
from typing import Any

from flask import Flask, jsonify, render_template, request, session
from werkzeug.middleware.proxy_fix import ProxyFix

from .config import AppConfig
from .redis_store import RedisStore
from .security import (
    ValidationError,
    csrf_required,
    ensure_sid,
    get_csrf_token,
    install_security_headers,
    json_error,
    rate_limited,
    require_json_body,
    require_str,
    TokenBucketRateLimiter,
    validate_category,
    validate_email,
    validate_item_type,
    validate_magnet,
    validate_order,
    validate_password,
    validate_positive_int,
    validate_query,
    validate_sort,
)
from .services import CloudService, SearchService, format_size, _safe_int
from .store import NotAuthenticated, TTLStore

log = logging.getLogger(__name__)


def create_app(
    config: AppConfig | None = None,
    *,
    cloud_service: CloudService | None = None,
    search_service: SearchService | None = None,
    client_store: TTLStore[Any] | None = None,
) -> Flask:
    config = config or AppConfig.from_env()
    app = Flask(__name__)
    app.wsgi_app = ProxyFix(app.wsgi_app, x_for=1, x_proto=1, x_host=1)
    app.config.update(
        SECRET_KEY=config.secret_key,
        SESSION_COOKIE_HTTPONLY=True,
        SESSION_COOKIE_SAMESITE="Lax",
        SESSION_COOKIE_SECURE=config.environment == "production",
        MAX_CONTENT_LENGTH=config.max_json_bytes,
        JSON_SORT_KEYS=False,
    )
    install_security_headers(app)

    limiter = TokenBucketRateLimiter(config.rate_limit_capacity, config.rate_limit_refill_per_second)
    cloud = cloud_service or CloudService(config)
    search = search_service or SearchService(config)
    store = client_store or TTLStore[Any](config.session_ttl_seconds, config.client_store_max_entries)

    rs: RedisStore | None = None
    if config.upstash_redis_url and config.upstash_redis_token:
        rs = RedisStore(config.upstash_redis_url, config.upstash_redis_token)
        if rs:
            try:
                rs.get("streamly:health_check_test")
                log.info("Upstash Redis reachable — history and token persistence active")
            except Exception:
                log.warning(
                    "Upstash Redis unreachable — history and token persistence disabled. "
                    "Check UPSTASH_REDIS_REST_URL and UPSTASH_REDIS_REST_TOKEN in your environment."
                )

    def _try_restore_from_refresh(sid: str):
        if not rs:
            raise NotAuthenticated("Not authenticated")
        rt = rs.get_refresh_token()
        if not rt:
            raise NotAuthenticated("Not authenticated")
        try:
            client, username = cloud.login_with_saved_token(rt)
        except PermissionError:
            rs.delete_refresh_token()
            raise NotAuthenticated("Refresh token invalid")
        store.put(sid, client)
        session["username"] = username
        new_rt = CloudService.serialize_token(client)
        if new_rt:
            rs.set_refresh_token(new_rt)
        log.info("Session restored via global master token for sid=%s...", sid[:8])
        return client

    def current_client():
        sid = session.get("sid")
        if not sid:
            sid = ensure_sid()
        try:
            return store.get(sid)
        except NotAuthenticated:
            try:
                return _try_restore_from_refresh(sid)
            except NotAuthenticated:
                pass
            if config.seedr_email and config.seedr_password:
                try:
                    client, username = cloud.login(config.seedr_email, config.seedr_password)
                    store.put(sid, client)
                    session["username"] = username
                    if rs:
                        rt = CloudService.serialize_token(client)
                        if rt:
                            rs.set_refresh_token(rt)
                    log.info("Auto-logged in headless mode for sid=%s", sid[:8])
                    return client
                except PermissionError:
                    log.error("Headless auto-login failed: invalid SEEDR_EMAIL/SEEDR_PASSWORD")
                except ConnectionError:
                    raise
                except Exception:
                    log.exception("Unexpected error during headless auto-login")
            raise NotAuthenticated("Not authenticated")

    @app.errorhandler(ValidationError)
    def handle_validation(exc: ValidationError):
        return json_error(400, "bad_request", str(exc))

    @app.errorhandler(NotAuthenticated)
    def handle_not_authenticated(exc: NotAuthenticated):
        return json_error(401, "unauthorized", "Login required")

    @app.errorhandler(PermissionError)
    def handle_permission(exc: PermissionError):
        return json_error(401, "authentication_failed", "Authentication failed or provider unavailable")

    @app.errorhandler(404)
    def handle_404(exc):
        return json_error(404, "not_found", "Not found")

    @app.errorhandler(ConnectionError)
    def handle_connection_error(exc: ConnectionError):
        return json_error(502, "bad_gateway", "Upstream provider error")

    @app.errorhandler(Exception)
    def handle_exception(exc: Exception):
        request_id = request.headers.get("X-Request-ID") or secrets.token_hex(8)
        log.exception("Unhandled error request_id=%s", request_id)
        response = json_error(500, "internal_error", "Internal server error")
        response.headers["X-Request-ID"] = request_id
        return response

    @app.get("/")
    def index():
        ensure_sid()
        import os as _os
        static_dir = _os.path.join(_os.path.dirname(__file__), "static")
        try:
            asset_ver = int(max(
                _os.path.getmtime(_os.path.join(root, f))
                for root, _dirs, files in _os.walk(static_dir)
                for f in files
            ))
        except ValueError:
            asset_ver = 1
        return render_template(
            "index.html", csrf_token=get_csrf_token(), asset_ver=asset_ver
        )

    @app.get("/healthz")
    def healthz():
        return jsonify({"ok": True})

    @app.get("/api/csrf")
    @rate_limited(limiter, cost=0.2)
    def csrf():
        ensure_sid()
        return jsonify({"success": True, "csrfToken": get_csrf_token()})

    @app.get("/api/status")
    @rate_limited(limiter, cost=0.2)
    def status_route():
        current_client()
        return jsonify({"success": True, "authenticated": True, "username": session.get("username", "")})

    @app.post("/api/login")
    @rate_limited(limiter, cost=5.0)
    @csrf_required
    def login():
        data = require_json_body(config)
        email = validate_email(require_str(data, "email", max_len=320))
        password = validate_password(data.get("password", data.get("pass")))
        sid = ensure_sid()
        client, username = cloud.login(email, password)
        store.put(sid, client)
        session["username"] = username
        if rs:
            rt = CloudService.serialize_token(client)
            if rt:
                rs.set_refresh_token(rt)
        return jsonify({"success": True, "username": username})

    @app.post("/api/login/silent")
    @rate_limited(limiter, cost=1.0)
    def login_silent():
        sid = session.get("sid") or ensure_sid()
        try:
            current_client()
            return jsonify({"success": True, "username": session.get("username", "")})
        except NotAuthenticated:
            return json_error(401, "no_refresh_token", "No valid refresh token stored")

    @app.get("/fs/folder/<folder_id>/items")
    @rate_limited(limiter, cost=1.0)
    def list_items(folder_id: str):
        folder = validate_positive_int(folder_id, name="folder_id", maximum=config.max_folder_id)
        try:
            data = cloud.list_items(current_client(), folder)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Provider error on list: %s", e)
            return json_error(502, "provider_error", "Provider unavailable or failed to list items")
        for item in data["folders"] + data["files"]:
            item["size_str"] = format_size(item["size"])
        return jsonify(data)

    @app.post("/api/delete")
    @rate_limited(limiter, cost=2.0)
    @csrf_required
    def delete_item():
        data = require_json_body(config)
        item_type = validate_item_type(data.get("type"))
        item_id = validate_positive_int(data.get("id"), name="id", maximum=config.max_file_id)
        try:
            cloud.delete_item(current_client(), item_type, item_id)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Provider error on delete: %s", e)
            return json_error(502, "provider_error", "Provider rejected the request or is unavailable")
        return jsonify({"success": True})

    @app.post("/api/zip")
    @rate_limited(limiter, cost=2.0)
    @csrf_required
    def zip_item():
        data = require_json_body(config)
        item_type = validate_item_type(data.get("type"))
        item_id = validate_positive_int(data.get("id"), name="id", maximum=config.max_file_id)
        try:
            url = cloud.get_zip_url(current_client(), item_type, item_id)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Provider error on zip: %s", e)
            return json_error(502, "provider_error", "Failed to create zip — provider unavailable")
        return jsonify({"success": bool(url), "url": url})

    @app.post("/api/delete/bulk")
    @rate_limited(limiter, cost=3.0)
    @csrf_required
    def delete_bulk():
        data = require_json_body(config)
        items = data.get("items")
        if not isinstance(items, list) or not items:
            return json_error(400, "bad_request", "items must be a non-empty list")
        if len(items) > 100:
            return json_error(400, "bad_request", "Too many items (max 100)")
        client = current_client()
        results = []
        for item in items:
            if not isinstance(item, dict):
                continue
            try:
                item_type = validate_item_type(item.get("type"))
                item_id = validate_positive_int(item.get("id"), name="id", maximum=config.max_file_id)
                cloud.delete_item(client, item_type, item_id)
                results.append({"id": item_id, "type": item_type, "ok": True})
            except (ConnectionError, TimeoutError) as exc:
                log.warning("Bulk delete item failed: %s", exc)
                results.append({"id": item.get("id"), "type": item.get("type"), "ok": False, "error": "Failed to delete item"})
            except ValidationError as exc:
                results.append({"id": item.get("id"), "type": item.get("type"), "ok": False, "error": "Invalid item data"})
        return jsonify({"success": True, "results": results})

    @app.post("/api/zip/bulk")
    @rate_limited(limiter, cost=3.0)
    @csrf_required
    def zip_bulk():
        data = require_json_body(config)
        items = data.get("items")
        if not isinstance(items, list) or not items:
            return json_error(400, "bad_request", "items must be a non-empty list")
        if len(items) > 100:
            return json_error(400, "bad_request", "Too many items (max 100)")
        validated = []
        for item in items:
            if not isinstance(item, dict):
                continue
            item_type = validate_item_type(item.get("type"))
            item_id = validate_positive_int(item.get("id"), name="id", maximum=config.max_file_id)
            validated.append({"type": item_type, "id": item_id})
        if not validated:
            return json_error(400, "bad_request", "No valid items")
        try:
            url = cloud.get_zip_url_bulk(current_client(), validated)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Bulk zip failed: %s", e)
            return json_error(502, "provider_error", "Failed to create zip — provider unavailable")
        return jsonify({"success": bool(url), "url": url})

    @app.post("/api/add")
    @rate_limited(limiter, cost=2.0)
    @csrf_required
    def add_magnet():
        data = require_json_body(config)
        magnet = validate_magnet(data.get("magnet"), config)
        raw_size = data.get("size")
        if raw_size is not None:
            size_bytes = _safe_int(raw_size)
            if size_bytes > 0:
                try:
                    storage = cloud.list_items(current_client(), 0)
                    used = max(0, _safe_int(storage.get("used")))
                    maximum = max(1, _safe_int(storage.get("max")))
                    if used + size_bytes > maximum:
                        return json_error(
                            400,
                            "storage_full",
                            "Not enough space. Clear some files from Seedr before adding."
                        )
                except (ConnectionError, TimeoutError) as e:
                    log.warning("Storage check failed before add, proceeding anyway: %s", e)
        try:
            cloud.add_magnet(current_client(), magnet)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Provider error on add: %s", e)
            return json_error(502, "provider_error", "Provider rejected the request (e.g. storage full) or is unavailable")
        return jsonify({"success": True})

    @app.get("/api/history")
    @rate_limited(limiter, cost=1.0)
    def get_history():
        try:
            items = rs.get_history("global_history") if rs else []
            return jsonify({"success": True, "items": items})
        except (ConnectionError, TimeoutError) as e:
            log.warning("Redis error on get_history: %s", e)
            return jsonify({"success": True, "items": [], "_warning": "History temporarily unavailable"})

    @app.post("/api/history/add")
    @csrf_required
    def add_history():
        data = require_json_body(config)
        magnet = validate_magnet(data.get("magnet"), config)
        name = require_str(data, "name", max_len=512) if data.get("name") else "Unknown Magnet"
        import time
        new_item = {
            "magnet": magnet,
            "title": name,
            "time": time.strftime("%d/%m/%Y, %H:%M:%S")
        }
        items = rs.get_history("global_history") if rs else []
        items = [it for it in items if it.get("magnet") != magnet]
        items.insert(0, new_item)
        items = items[:50]
        if rs:
            if not rs.save_history("global_history", items):
                log.warning("Failed to persist history to Redis")
        return jsonify({"success": True})

    @app.post("/api/history/delete")
    @csrf_required
    def delete_history():
        data = require_json_body(config)
        magnet = data.get("magnet")
        if not magnet:
            return json_error(400, "bad_request", "Missing magnet link")
        items = rs.get_history("global_history") if rs else []
        new_items = [it for it in items if it.get("magnet") != magnet]
        if len(items) != len(new_items) and rs:
            rs.save_history("global_history", new_items)
        return jsonify({"success": True})

    @app.post("/api/history/clear")
    @csrf_required
    def clear_history():
        if rs:
            rs.save_history("global_history", [])
        return jsonify({"success": True})

    @app.get("/api/url")
    @rate_limited(limiter, cost=1.0)
    def get_url():
        file_id = validate_positive_int(request.args.get("file_id"), name="file_id", maximum=config.max_file_id)
        try:
            url = cloud.get_stream_url(current_client(), file_id)
        except (ConnectionError, TimeoutError) as e:
            log.warning("Provider error on get_url: %s", e)
            return json_error(502, "provider_error", "Failed to get stream URL — provider unavailable")
        if not url:
            return json_error(404, "not_found", "Stream URL not available for this file")
        return jsonify({"success": True, "url": url})

    @app.get("/api/suggest")
    @rate_limited(limiter, cost=0.5)
    def suggest():
        q = validate_query(request.args.get("q"), config)
        return jsonify(search.imdb_suggestions(q))

    @app.get("/api/search")
    @rate_limited(limiter, cost=1.0)
    def search_route():
        q = validate_query(request.args.get("q"), config)
        category = validate_category(request.args.get("category"), config)
        sort = validate_sort(request.args.get("sort"), config)
        order = validate_order(request.args.get("order"), config)
        page = validate_positive_int(request.args.get("page", 1), name="page", maximum=10_000)
        page = max(1, page)
        try:
            raw_payload = search.bitsearch(q, category, sort, order, page)
        except TypeError:
            raw_payload = search.bitsearch(q, category, sort, order)
        if isinstance(raw_payload, dict):
            raw_items = raw_payload.get("results", []) if isinstance(raw_payload.get("results", []), list) else []
            pagination = raw_payload.get("pagination", {}) if isinstance(raw_payload.get("pagination", {}), dict) else {}
            took = raw_payload.get("took")
        else:
            raw_items = raw_payload if isinstance(raw_payload, list) else []
            pagination = {"page": page, "perPage": len(raw_items), "total": len(raw_items), "totalPages": 1, "hasNext": False, "hasPrev": page > 1}
            took = None
        category_labels = {"1": "Other", "2": "Movies", "3": "TV Shows", "4": "Anime", "5": "Software", "6": "Games", "7": "Music", "8": "Audiobooks", "9": "Ebooks", "10": "Adult"}
        rows = []
        for item in raw_items:
            infohash = str(item.get("infohash", ""))[:128]
            title = str(item.get("title", ""))[:512]
            if not infohash or not title:
                continue
            raw_category = str(item.get("category", "Other"))[:64]
            raw_size = item.get("size")
            rows.append(
                {
                    "name": title,
                    "size": format_size(_safe_int(raw_size)),
                    "size_bytes": max(0, _safe_int(raw_size)),
                    "seeds": int(item.get("seeders", 0) or 0),
                    "leeches": int(item.get("leecher", 0) or 0),
                    "date": str(item.get("createdAt", "")).split("T")[0][:32],
                    "category": category_labels.get(raw_category, raw_category or "Other"),
                    "magnet": f"magnet:?xt=urn:btih:{infohash}&dn={title}",
                }
            )
        return jsonify({"results": rows, "pagination": pagination, "took": took})

    return app


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    logging.getLogger("httpx").setLevel(logging.WARNING)
    logging.getLogger("httpcore").setLevel(logging.WARNING)
    logging.getLogger("urllib3").setLevel(logging.WARNING)
    port = int(os.getenv("PORT", "5000"))
    host = os.getenv("HOST", "127.0.0.1")
    create_app().run(host=host, port=port, debug=False)

from __future__ import annotations

from contextlib import contextmanager
from dataclasses import dataclass
import ipaddress
import logging
import socket
import threading
import time
from typing import Any, Callable, Protocol
from urllib.parse import quote

import requests

from .config import AppConfig
from .security import ValidationError

log = logging.getLogger(__name__)


class SeedrClientProtocol(Protocol):
    token: Any

    def get_settings(self) -> Any: ...
    def list_contents(self, folder_id: int) -> Any: ...
    def delete_folder(self, folder_id: int) -> Any: ...
    def delete_file(self, file_id: int) -> Any: ...
    def add_torrent(self, magnet: str) -> Any: ...
    def fetch_file(self, file_id: int) -> Any: ...


ClientFactory = Callable[[str, str], SeedrClientProtocol]


def default_seedr_client_factory(email: str, password: str) -> SeedrClientProtocol:
    from seedrcc import Seedr
    return Seedr.from_password(email, password)


def _safe_int(value: Any, default: int = 0) -> int:
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _safe_name(value: Any) -> str:
    if not isinstance(value, str):
        value = str(value or "")
    return "".join(ch for ch in value if ch >= " " and ch != "\x7f")[:512]


class CloudService:
    def __init__(self, config: AppConfig, client_factory: ClientFactory = default_seedr_client_factory):
        self.config = config
        self.client_factory = client_factory
        self.http = requests.Session()

    def login(self, email: str, password: str) -> tuple[SeedrClientProtocol, str]:
        try:
            client = self.client_factory(email, password)
            settings = client.get_settings()
            username = _safe_name(getattr(getattr(settings, "account", None), "username", ""))
            return client, username
        except requests.RequestException as e:
            log.warning("Seedr network/provider error during login: %s", e)
            raise ConnectionError("Provider unavailable") from None
        except Exception:
            log.exception("Seedr login failed")
            raise PermissionError("Invalid credentials") from None

    def login_with_saved_token(self, token_b64: str) -> tuple[SeedrClientProtocol, str]:
        if not token_b64 or not isinstance(token_b64, str):
            raise PermissionError("No saved token available")
        try:
            from seedrcc import Seedr
            from seedrcc.token import Token
            token = Token.from_base64(token_b64)
            client = Seedr(token=token)
            settings = client.get_settings()
            username = _safe_name(getattr(getattr(settings, "account", None), "username", ""))
            return client, username
        except requests.RequestException as e:
            log.warning("Seedr network/provider error during saved-token login: %s", e)
            raise ConnectionError("Provider unavailable") from None
        except Exception:
            log.exception("Seedr saved-token login failed")
            raise PermissionError("Saved token invalid or expired") from None

    @staticmethod
    def serialize_token(client: SeedrClientProtocol) -> str | None:
        """Serialize Token to base64 for Redis persistence. Returns None on failure."""
        token_obj = getattr(client, "token", None)
        if token_obj is None:
            return None
        try:
            b64 = token_obj.to_base64()
            if not isinstance(b64, str) or not b64:
                return None
            return b64
        except Exception:
            return None

    def list_items(self, client: SeedrClientProtocol, folder_id: int) -> dict[str, Any]:
        contents = client.list_contents(folder_id)
        settings = client.get_settings()
        account = getattr(settings, "account", None)
        return {
            "parent": _safe_int(getattr(contents, "parent_id", 0)),
            "folders": [
                {
                    "id": _safe_int(getattr(folder, "id", 0)),
                    "name": _safe_name(getattr(folder, "name", "")),
                    "size": max(0, _safe_int(getattr(folder, "size", 0))),
                    "last_update": getattr(folder, "last_update", None),
                }
                for folder in list(getattr(contents, "folders", []) or [])[:1000]
            ],
            "files": [
                {
                    "id": _safe_int(getattr(file, "folder_file_id", 0)),
                    "name": _safe_name(getattr(file, "name", "")),
                    "size": max(0, _safe_int(getattr(file, "size", 0))),
                    "last_update": getattr(file, "last_update", None),
                }
                for file in list(getattr(contents, "files", []) or [])[:1000]
            ],
            "used": max(0, _safe_int(getattr(account, "space_used", 0))),
            "max": max(1, _safe_int(getattr(account, "space_max", 1), 1)),
        }

    def delete_item(self, client: SeedrClientProtocol, item_type: str, item_id: int) -> None:
        if item_type == "folder":
            client.delete_folder(item_id)
        elif item_type == "file":
            client.delete_file(item_id)
        else:
            raise ValidationError("Invalid type")

    def add_magnet(self, client: SeedrClientProtocol, magnet: str) -> None:
        client.add_torrent(magnet)

    def get_stream_url(self, client: SeedrClientProtocol, file_id: int) -> str:
        try:
            url = getattr(client.fetch_file(file_id), "url", "")
            if not isinstance(url, str) or not url.startswith(("https://", "http://")):
                return ""
            return url
        except requests.RequestException as e:
            log.warning("Provider error fetching stream URL: %s", e)
            raise ConnectionError("Provider unavailable") from None
        except Exception:
            log.exception("Failed fetching stream URL")
            return ""

    def _fetch_archive_url(self, token: str, archive_arr: list) -> str:
        try:
            response = self.http.post(
                "https://www.seedr.cc/oauth_test/resource.php",
                data={
                    "access_token": token,
                    "func": "fetch_archive",
                    "archive_arr": __import__("json").dumps(archive_arr, separators=(",", ":")),
                },
                timeout=self.config.archive_timeout_seconds,
            )
            response.raise_for_status()
            payload = response.json()
            url = payload.get("archive_url") or payload.get("url") or ""
            if isinstance(url, str) and url.startswith(("http://", "https://")):
                return url
            return ""
        except requests.RequestException as e:
            log.warning("Archive URL request failed: %s", e)
            raise ConnectionError("Provider unavailable") from None
        except Exception:
            log.exception("Failed fetching archive URL")
            return ""

    def get_zip_url_bulk(self, client: SeedrClientProtocol, items: list) -> str:
        token_obj = getattr(client, "token", None)
        token = getattr(token_obj, "access_token", None)
        if not isinstance(token, str) or not token:
            raise PermissionError("Provider token unavailable")
        result = self._fetch_archive_url(token, items)
        if not result:
            raise ConnectionError("Failed to create zip — provider returned no URL")
        return result

    def get_zip_url(self, client: SeedrClientProtocol, item_type: str, item_id: int) -> str:
        token_obj = getattr(client, "token", None)
        token = getattr(token_obj, "access_token", None)
        if not isinstance(token, str) or not token:
            raise PermissionError("Provider token unavailable")
        return self._fetch_archive_url(token, [{"type": item_type, "id": item_id}])


_BITSEARCH_DNS_LOCK = threading.RLock()
_BITSEARCH_IP_CACHE: tuple[str, float] | None = None


def _is_name_resolution_error(exc: BaseException) -> bool:
    text = str(exc).lower()
    return "name or service not known" in text or "getaddrinfo failed" in text or "failed to resolve" in text


def _resolve_bitsearch_via_doh(timeout: float) -> str | None:
    global _BITSEARCH_IP_CACHE
    now = time.monotonic()
    if _BITSEARCH_IP_CACHE and _BITSEARCH_IP_CACHE[1] > now:
        return _BITSEARCH_IP_CACHE[0]
    try:
        response = requests.get(
            "https://1.1.1.1/dns-query",
            params={"name": "bitsearch.eu", "type": "A"},
            headers={"accept": "application/dns-json", "User-Agent": "Streamly/1.0"},
            timeout=timeout,
        )
        response.raise_for_status()
        data = response.json()
        for answer in data.get("Answer", []) if isinstance(data, dict) else []:
            candidate = answer.get("data")
            try:
                ip = ipaddress.ip_address(candidate)
            except ValueError:
                continue
            if ip.version == 4 and not (ip.is_private or ip.is_loopback or ip.is_link_local or ip.is_multicast):
                _BITSEARCH_IP_CACHE = (str(ip), now + 300)
                return str(ip)
    except (requests.RequestException, ValueError) as exc:
        log.warning("Cloudflare DoH fallback for bitsearch.eu failed: %s", exc)
    return None


@contextmanager
def _temporary_bitsearch_resolution(ip: str):
    old_getaddrinfo = socket.getaddrinfo

    def patched_getaddrinfo(host, port, family=0, type=0, proto=0, flags=0):
        if host == "bitsearch.eu":
            return old_getaddrinfo(ip, port, family or socket.AF_INET, type, proto, flags)
        return old_getaddrinfo(host, port, family, type, proto, flags)

    with _BITSEARCH_DNS_LOCK:
        socket.getaddrinfo = patched_getaddrinfo
        try:
            yield
        finally:
            socket.getaddrinfo = old_getaddrinfo


class SearchService:
    def __init__(self, config: AppConfig):
        self.config = config
        self.http = requests.Session()

    def imdb_suggestions(self, q: str) -> list[dict[str, Any]]:
        url = self.config.imdb_suggest_template.format(query=quote(q.lower(), safe=""))
        try:
            response = self.http.get(url, timeout=self.config.request_timeout_seconds)
            response.raise_for_status()
            data = response.json()
        except (requests.RequestException, ValueError):
            log.info("IMDb suggestion request failed", exc_info=True)
            return []
        suggestions: list[dict[str, Any]] = []
        for item in data.get("d", []) if isinstance(data, dict) else []:
            imdb_id = item.get("id")
            if not isinstance(imdb_id, str) or not imdb_id.startswith("tt"):
                continue
            image = item.get("i", {}) if isinstance(item.get("i"), dict) else {}
            suggestions.append(
                {
                    "title": _safe_name(item.get("l", "")),
                    "year": item.get("y", "N/A"),
                    "poster": image.get("imageUrl", "") if isinstance(image.get("imageUrl", ""), str) else "",
                    "id": imdb_id,
                }
            )
            if len(suggestions) >= 10:
                break
        return suggestions

    def bitsearch(self, q: str, category: str, sort: str, order: str, page: int = 1) -> dict[str, Any]:
        page = max(1, int(page or 1))
        params = {"q": q, "sort": sort, "order": order, "page": page, "limit": 50}
        if category:
            params["category"] = category

        def request_payload() -> dict[str, Any]:
            response = self.http.get(
                self.config.bitsearch_url,
                params=params,
                headers={"User-Agent": "Streamly/1.0"},
                timeout=self.config.request_timeout_seconds,
            )
            response.raise_for_status()
            data = response.json()
            return data if isinstance(data, dict) else {}

        try:
            payload = request_payload()
        except (requests.RequestException, ValueError) as exc:
            if not _is_name_resolution_error(exc):
                log.warning("Bitsearch request failed: %s", exc)
                return {"results": [], "pagination": {"page": page, "perPage": 50, "total": 0, "totalPages": 1, "hasNext": False, "hasPrev": page > 1}, "took": None}
            ip = _resolve_bitsearch_via_doh(self.config.request_timeout_seconds)
            if not ip:
                log.warning("Bitsearch DNS failed and DoH fallback returned no usable IP: %s", exc)
                return {"results": [], "pagination": {"page": page, "perPage": 50, "total": 0, "totalPages": 1, "hasNext": False, "hasPrev": page > 1}, "took": None}
            try:
                with _temporary_bitsearch_resolution(ip):
                    payload = request_payload()
                log.info("Bitsearch request succeeded through scoped DNS fallback ip=%s", ip)
            except (requests.RequestException, ValueError) as retry_exc:
                log.warning("Bitsearch request failed after DNS fallback: %s", retry_exc)
                return {"results": [], "pagination": {"page": page, "perPage": 50, "total": 0, "totalPages": 1, "hasNext": False, "hasPrev": page > 1}, "took": None}

        raw_results = payload.get("results", []) if isinstance(payload, dict) else []
        raw_results = raw_results[:50] if isinstance(raw_results, list) else []
        pagination = payload.get("pagination", {}) if isinstance(payload.get("pagination", {}), dict) else {}

        def as_int(*values: Any, default: int = 0) -> int:
            for value in values:
                try:
                    if value is not None and value != "":
                        return int(value)
                except (TypeError, ValueError):
                    continue
            return default

        per_page = as_int(pagination.get("perPage"), pagination.get("limit"), payload.get("perPage"), payload.get("limit"), default=50)
        per_page = max(1, min(50, per_page))
        total = as_int(
            pagination.get("total"), pagination.get("totalResults"), pagination.get("count"),
            payload.get("total"), payload.get("totalResults"), payload.get("count"),
            default=len(raw_results),
        )
        total_pages = as_int(
            pagination.get("totalPages"), pagination.get("pages"),
            payload.get("totalPages"), payload.get("pages"),
            default=max(1, (total + per_page - 1) // per_page),
        )
        return {
            "results": raw_results,
            "pagination": {
                "page": as_int(pagination.get("page"), payload.get("page"), default=page),
                "perPage": per_page,
                "total": total,
                "totalPages": total_pages,
                "hasNext": bool(pagination.get("hasNext", page < total_pages)),
                "hasPrev": bool(pagination.get("hasPrev", page > 1)),
            },
            "took": payload.get("took"),
        }


def format_size(num_bytes: int) -> str:
    b = max(0, int(num_bytes))
    if b >= 1024**4: return f"{b / (1024**4):.2f} TB"
    if b >= 1024**3: return f"{b / (1024**3):.2f} GB"
    if b >= 1024**2: return f"{b / (1024**2):.1f} MB"
    if b >= 1024:    return f"{b / 1024:.1f} KB"
    return f"{b} B"

"""Upstash Redis REST client wrapper.

Uses Upstash HTTP REST API (no redis-py / no TCP socket needed).
Sends commands as JSON arrays: ["SET", "key", "value"]
See: https://upstash.com/docs/redis/features/restapi
"""
from __future__ import annotations

import json as _json
import logging
import secrets
from typing import Optional, Any

import requests

log = logging.getLogger(__name__)

_SECRET_KEY = "streamly:secret_key"
_REFRESH_TTL_SECONDS = 60 * 60 * 24 * 30  # 30 days


class RedisStore:
    def __init__(self, url: str, token: str, timeout: float = 5.0):
        self.url = url.rstrip("/")
        self.token = token
        self.timeout = timeout
        self._headers = {"Authorization": f"Bearer {token}"}

    def _execute(self, *command: str) -> Optional[Any]:
        try:
            r = requests.post(self.url, headers=self._headers, json=list(command), timeout=self.timeout)
            r.raise_for_status()
            return r.json().get("result")
        except requests.RequestException as e:
            log.warning("Upstash request failed: %s", e)
            return None

    def get(self, key: str) -> Optional[str]:
        result = self._execute("GET", key)
        return result if isinstance(result, str) else None

    def set(self, key: str, value: str) -> bool:
        cleaned = self._strip_wrapping_quotes(value)
        return self._execute("SET", key, cleaned) == "OK"

    @staticmethod
    def _strip_wrapping_quotes(value: str) -> str:
        s = (value or "").strip()
        while len(s) >= 2 and ((s[0] == '"' and s[-1] == '"') or (s[0] == "'" and s[-1] == "'")):
            s = s[1:-1].strip()
        s = s.replace('\\"', '"').replace("\\", "\\")
        return s

    def get_or_create_secret(self) -> str:
        existing = self.get(_SECRET_KEY)
        if existing:
            return existing
        new_secret = secrets.token_hex(32)
        if self.set(_SECRET_KEY, new_secret):
            log.info("Generated and persisted new SECRET_KEY to Upstash")
            return new_secret
        log.warning("Could not persist SECRET_KEY; using ephemeral")
        return new_secret

    def get_refresh_token(self) -> Optional[str]:
        return self.get("streamly:master_refresh_token")

    def set_refresh_token(self, token: str | None) -> bool:
        """Persist token to Redis with 30-day TTL. Rejects falsy values."""
        if not token:
            log.warning("set_refresh_token called with empty/None value — skipping Redis write")
            return False
        cleaned = self._strip_wrapping_quotes(token)
        return self._execute("SET", "streamly:master_refresh_token", cleaned, "EX", str(_REFRESH_TTL_SECONDS)) == "OK"

    def delete_refresh_token(self) -> bool:
        return self._execute("DEL", "streamly:master_refresh_token") is not None

    def get_history(self, sid: str) -> list[dict[str, Any]]:
        raw = self.get(f"streamly:history:{sid}")
        if not raw:
            return []
        try:
            return _json.loads(raw)
        except Exception:
            return []

    def save_history(self, sid: str, items: list[dict[str, Any]]) -> bool:
        """Save history to Redis. Returns True on success, False on failure."""
        return self.set(f"streamly:history:{sid}", _json.dumps(items))

async function search(keepPage, page) {
  const q = $("searchQuery").value.trim();
  if (!q) return status($("searchStatus"), "Enter a search query", "error");

  clearTimeout(suggestTimer);
  $("suggestBox").classList.add("hidden");
  $("suggestBox").textContent = "";

  if (/^magnet:\?xt=urn:btih:/i.test(q)) {
    let magnetName = "Unknown Magnet";
    const dnMatch = q.match(/[?&]dn=([^&]+)/);
    if (dnMatch) {
      try { magnetName = decodeURIComponent(dnMatch[1].replace(/\+/g, " ")); } catch (_) {}
    }
    saveToHistory(q, magnetName);
    status($("searchStatus"), "Adding magnet to Seedr...", "");
    try {
      await postJson("/api/add", { magnet: q });
      status($("searchStatus"), "\u2713 Added: " + magnetName, "ok");
      $("searchQuery").value = "";
    } catch (err) {
      status($("searchStatus"), err.message || "Failed to add magnet", "error");
    }
    return;
  }

  if (!keepPage) currentPage = page || 1;
  status($("searchStatus"), "Searching...", "");
  $("pagination").classList.add("hidden");
  $("pagination").textContent = "";
  try {
    const params = new URLSearchParams();
    params.set("q", q);
    params.set("category", $("category").value || "");
    params.set("sort", currentSort);
    params.set("order", currentOrder);
    params.set("page", String(currentPage));
    const data = await parseResponse(await fetch("/api/search?" + params.toString(), { credentials: "same-origin" }));
    const results = Array.isArray(data.results) ? data.results : [];
    $("results").classList.remove("hidden");
    renderSearchTable(results);
    renderPagination(data.pagination, data.took, data.results ? data.results.length : 0);
    status($("searchStatus"), "Found " + results.length + " result(s)", "ok");
  } catch (err) {
    status($("searchStatus"), err.message || "Search failed", "error");
  }
}

function renderPagination(pagination, took, count) {
  const box = $("pagination");
  box.textContent = "";
  if (!pagination || (!pagination.total && !count)) return;
  const page = Number(pagination.page) || 1;
  const totalPages = Number(pagination.totalPages) || 1;
  const total = Number(pagination.total) || 0;
  const isNarrow = window.innerWidth < 500;

  function addButton(label, num, disabled, active) {
    const btn = document.createElement("button");
    btn.className = "page-btn" + (active ? " active" : "");
    btn.textContent = label;
    btn.disabled = disabled;
    btn.addEventListener("click", () => {
      currentPage = num;
      search(true, num);
      window.scrollTo({ top: ($("searchView").offsetTop || 200) - 100, behavior: "smooth" });
    });
    box.appendChild(btn);
  }

  addButton("\u2039", Math.max(1, page - 1), page <= 1, false);

  if (isNarrow) {
    addButton(String(page), page, false, true);
  } else {
    const pages = new Set([1, totalPages, page, page - 1, page + 1]);
    for (let i = 1; i <= Math.min(totalPages, 3); i++) pages.add(i);
    for (let i = Math.max(1, totalPages - 2); i <= totalPages; i++) pages.add(i);
    const ordered = [...pages].filter(n => n >= 1 && n <= totalPages).sort((a, b) => a - b);
    let last = 0;
    for (const n of ordered) {
      if (last && n > last + 1) {
        const gap = document.createElement("span");
        gap.className = "muted";
        gap.textContent = "...";
        box.appendChild(gap);
      }
      addButton(String(n), n, false, n === page);
      last = n;
    }
  }

  addButton("\u203A", Math.min(totalPages, page + 1), page >= totalPages, false);

  const info = document.createElement("div");
  info.className = "page-info";
  const tookText = typeof took === "number" ? " in " + took + "ms" : "";
  const perPage = Number(pagination.perPage || 50);
  info.textContent = total ? "Page " + page + " of " + totalPages + " (" + total + " results, " + perPage + "/page" + tookText + ")" : "Page " + page + " of " + totalPages;
  box.appendChild(info);
  box.classList.remove("hidden");
}

function renderSearchTable(results) {
  const body = $("torrentBody");
  const mobile = $("mobileResults");
  body.textContent = "";
  mobile.textContent = "";
  syncSortControls();
  for (const result of results) {
    const tr = document.createElement("tr");

    const name = document.createElement("td");
    name.className = "torrent-name";
    const nameText = document.createElement("div");
    nameText.className = "truncate";
    nameText.title = result.name || "";
    nameText.textContent = result.name || "Untitled";
    name.appendChild(nameText);

    const seeds = document.createElement("td");
    seeds.className = "num seed";
    seeds.textContent = result.seeds || 0;

    const date = document.createElement("td");
    date.className = "muted";
    date.textContent = result.date || "-";

    const size = document.createElement("td");
    size.className = "num muted";
    size.textContent = result.size || "-";

    const addTd = document.createElement("td");
    addTd.appendChild(makeAddButton(result));
    tr.append(name, seeds, date, size, addTd);
    body.appendChild(tr);

    const card = document.createElement("div");
    card.className = "mobile-result";
    const cardTitle = document.createElement("div");
    cardTitle.className = "result-title";
    cardTitle.textContent = result.name || "Untitled";
    const meta = document.createElement("div");
    meta.className = "mobile-meta";
    for (const part of ["Seeds: " + (result.seeds || 0), "Leeches: " + (result.leeches || 0), "Size: " + (result.size || "?"), "Date: " + (result.date || "?"), result.category || "Other"]) {
      const span = document.createElement("span");
      span.textContent = part;
      meta.appendChild(span);
    }
    const actions = document.createElement("div");
    actions.style.marginTop = "10px";
    actions.appendChild(makeAddButton(result));
    card.append(cardTitle, meta, actions);
    mobile.appendChild(card);
  }
}

function makeAddButton(result) {
  const add = document.createElement("button");
  add.type = "button";
  add.className = "add-btn";
  add.dataset.state = "idle";
  add.textContent = "Add";
  add.addEventListener("click", async () => {
    saveToHistory(result.magnet, result.name);
    add.disabled = true;
    add.dataset.state = "adding";
    add.textContent = "Adding...";
    try {
      await postJson("/api/add", { magnet: result.magnet, size: result.size_bytes || 0 });
      toast("Added to Seedr: " + (result.name || "torrent"));
      add.dataset.state = "done";
      add.textContent = "\u2713 Added";
    } catch (err) {
      toast(err.message || "Failed to add");
      add.dataset.state = "idle";
      add.textContent = "Add";
      add.disabled = false;
    }
  });
  return add;
}

#!/usr/bin/env python3
"""Self-verification gate. No Node required — runs anywhere Python does.

Usage:
    python check.py

Checks: JS bracket balance, CSS brace balance, Flask boots + serves 200,
pre-flight summary of implemented fixes.
"""
import os, shutil, subprocess, sys

ROOT = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
PKG  = os.path.join(ROOT, "streamly_hardened")


def preflight():
    app_py   = open(os.path.join(PKG, "app.py"), encoding="utf-8").read()
    svcs_py  = open(os.path.join(PKG, "services.py"), encoding="utf-8").read()
    redis_py = open(os.path.join(PKG, "redis_store.py"), encoding="utf-8").read()

    checks = []

    if "storage_full" in app_py and "used + size_bytes" in app_py:
        checks.append(("Storage check before add", True, "server-side"))
    else:
        checks.append(("Storage check before add", False, "not implemented"))

    if "return None" in svcs_py and 'if not token:' in redis_py:
        checks.append(("Empty token guard", True, "serialize returns None, Redis rejects empty"))
    else:
        checks.append(("Empty token guard", False, "not implemented"))

    if "Upstash Redis reachable" in app_py:
        checks.append(("Redis health check", True, "warns on startup if down"))
    else:
        checks.append(("Redis health check", False, "not implemented"))

    broad  = app_py.count("except Exception as")
    spec   = app_py.count("except (ConnectionError, TimeoutError)")
    if spec >= 6 and broad == 0:
        checks.append(("Specific exception handlers", True, f"{spec} specific, 0 broad"))
    elif spec > 0:
        checks.append(("Specific exception handlers", True, f"{spec} specific, {broad} broad (low risk)"))
    else:
        checks.append(("Specific exception handlers", False, "not implemented"))

    if broad == 0:
        checks.append(("Safe error messages", True, "no internal details leaked"))
    else:
        checks.append(("Safe error messages", False, f"{broad} broad handlers remain"))

    if "/api/logout" in app_py:
        checks.append(("Logout endpoint", True, "implemented"))
    else:
        checks.append(("Logout endpoint", False, "not implemented (user declined)"))

    print("\n===== Streamly Pre-Flight =====")
    done = sum(1 for _, s, _ in checks if s)
    for name, status, detail in checks:
        icon = "OK" if status else "XX"
        print(f"  [{icon}] {name}: {detail}")
    print(f"\n  {done}/{len(checks)} fixes implemented")
    print("===============================")
    return done == len(checks) - 1   # -1 for logout (user declined)


ok = True


def fail(msg):
    global ok
    ok = False
    print("  FAIL:", msg)


# Rebuild app.js
js_dir = os.path.join(PKG, "static", "js")
builder = os.path.join(js_dir, "build_js.py")
if os.path.exists(builder):
    print("-> Rebuild app.js")
    r = subprocess.run([sys.executable, builder], capture_output=True, text=True)
    print("  " + (r.stdout.strip() or r.stderr.strip()))
    if r.returncode != 0:
        fail("build_js.py failed")

print("-> Pre-flight summary")
preflight()

# JS check
print("\n-> JS bracket balance")
js_path = os.path.join(PKG, "static", "js", "app.js")
src = open(js_path, encoding="utf-8").read()

node = shutil.which("node")
if node:
    r = subprocess.run([node, "--check", js_path], capture_output=True, text=True)
    if r.returncode == 0:
        print("  node --check OK")
    else:
        fail("node --check: " + r.stderr.strip())
else:
    pairs = {")": "(", "]": "[", "}": "{"}
    opens = set("([{")
    stack, i, n, state = [], 0, len(src), None
    while i < n:
        c, nxt = src[i], src[i + 1] if i + 1 < n else ""
        if state in ("'", '"', "`"):
            if c == "\\": i += 2; continue
            if c == state: state = None
        elif state == "//":
            if c == "\n": state = None
        elif state == "/*":
            if c == "*" and nxt == "/": state = None; i += 2; continue
        else:
            if c in ("'", '"', "`"): state = c
            elif c == "/" and nxt == "/": state = "//"
            elif c == "/" and nxt == "*": state = "/*"
            elif c in opens: stack.append(c)
            elif c in pairs:
                if not stack or stack[-1] != pairs[c]: fail(f"unbalanced '{c}' at {i}"); break
                stack.pop()
        i += 1
    if ok and stack: fail(f"{len(stack)} unclosed")
    if ok: print("  bracket balance OK")

# CSS check
print("\n-> CSS brace balance")
for f in sorted(os.listdir(os.path.join(PKG, "static", "css"))):
    if not f.endswith(".css"): continue
    s = open(os.path.join(PKG, "static", "css", f), encoding="utf-8").read()
    o, c = s.count("{"), s.count("}")
    print(f"  {f}: {o} open / {c} close", "OK" if o == c else "MISMATCH")
    if o != c: fail(f"{f} brace mismatch")

# Flask check
print("\n-> Flask boots + serves 200")
os.environ.setdefault("SECRET_KEY", "check")
os.environ.setdefault("APP_ENV", "development")
sys.path.insert(0, ROOT)
try:
    from streamly_hardened.app import create_app
    c = create_app().test_client()
    for name, url in [("index", "/"), ("base.css", "/static/css/base.css"),
                      ("responsive.css", "/static/css/responsive.css"), ("app.js", "/static/js/app.js")]:
        code = c.get(url).status_code
        print(f"  {name}={code}", end="")
        if code != 200: fail(f"{name} returned {code}")
    print()
except Exception as e:
    fail(f"Flask error: {e}")

print()
if ok:
    print("OK - all checks passed")
    sys.exit(0)
print("FAILED - fix the issues above before committing")
sys.exit(1)
